INSERT INTO t_group_manager
(
	 GM_NAME
	, GM_SUMMARY
	, GM_PLACE
	, GM_DATE
	, GM_REGDT
	, GM_REGNM
	, GM_DIVISION
	, GM_MAXIMUM
	, GM_INTRODUCE
	, GM_HOLIDAY
	, GM_USE
	, GM_MN_HOMEDIV_C
)
VALUES
(
	 #{GM_NAME}
	, #{GM_SUMMARY}
	, #{GM_PLACE}
	, #{GM_DATE}
	, SYSDATE()
	, #{GM_REGNM}
	, #{GM_DIVISION}
	, #{GM_MAXIMUM}
	, #{GM_INTRODUCE}
	, #{GM_HOLIDAY}
	, #{GM_USE}
	, #{GM_MN_HOMEDIV_C}
)

