SELECT GSS.* , LEFT(GSS.GSS_ST_TIME, 2) ST_H , RIGHT(GSS.GSS_ST_TIME, 2) ST_M , LEFT(GSS.GSS_EN_TIME, 2) EN_H , RIGHT(GSS.GSS_EN_TIME, 2) EN_M FROM t_group_schedule_main GSM
LEFT JOIN t_group_schedule_sub GSS ON GSM.GSM_KEYNO = GSS.GSS_GSM_KEYNO
WHERE GSM_GM_KEYNO = #{GM_KEYNO}

